class Solution(object):
    def isValid(self, s):
        stack = []
        pairs = {'(': ')', '{': '}', '[': ']'}
        for char in s:
            if char in pairs:
                stack.append(char)
            else:
                if not stack or pairs[stack[-1]] != char:
                    return False
                stack.pop()
        return len(stack) == 0
